// Base64 encoded sprite sheets
const SPRITE_DATA = {
  heroes: 'data:image/png;base64,',
};

// Loaded Image objects
const SPRITES = {};
let _spritesLoaded = 0;
const _spritesTotal = 1;
let _spritesReady = false;

// Start loading immediately on script parse — don't wait for anything
(function preloadSpritesNow(){
  Object.entries(SPRITE_DATA).forEach(([name, src]) => {
    const img = new Image();
    img.onload = () => {
      SPRITES[name] = img;
      _spritesLoaded++;
      if(_spritesLoaded >= _spritesTotal){
        preprocessAllSprites();
        _spritesReady = true;
        console.log('Sprites ready!', Object.keys(SPRITE_CANVASES));
      }
    };
    img.onerror = (e) => console.error('Sprite load error:', name, e);
    img.src = src;
  });
})();

function loadSprites(onReady) {
  Object.entries(SPRITE_DATA).forEach(([name, src]) => {
    const img = new Image();
    img.onload = () => {
      SPRITES[name] = img;
      _spritesLoaded++;
      if(_spritesLoaded >= _spritesTotal) onReady();
    };
    img.src = src;
  });
}

// Background color removal via offscreen canvas
// We pre-process each sheet to remove the BG color
const SPRITE_CANVASES = {};

function preprocessSprite(name, bgRGB, tolerance=50) {
  const img = SPRITES[name];
  if(!img) return;
  const oc = document.createElement('canvas');
  oc.width = img.width; oc.height = img.height;
  const ctx = oc.getContext('2d');
  ctx.drawImage(img, 0, 0);
  const idata = ctx.getImageData(0,0,img.width,img.height);
  const d = idata.data;
  // Sample actual bg color from corner pixel for more accuracy
  const actualBg = [d[0], d[1], d[2]];
  for(let i=0;i<d.length;i+=4) {
    const r=d[i],g=d[i+1],b=d[i+2];
    // Match against both provided bgRGB and sampled corner color
    const matchProvided = Math.abs(r-bgRGB[0])<tolerance &&
                          Math.abs(g-bgRGB[1])<tolerance &&
                          Math.abs(b-bgRGB[2])<tolerance;
    const matchActual   = Math.abs(r-actualBg[0])<tolerance &&
                          Math.abs(g-actualBg[1])<tolerance &&
                          Math.abs(b-actualBg[2])<tolerance;
    if(matchProvided || matchActual) d[i+3]=0;
  }
  ctx.putImageData(idata,0,0);
  SPRITE_CANVASES[name] = oc;
  console.log(`Sprite ${name} processed: ${img.width}x${img.height}, bg sampled=${actualBg}`);
}

function preprocessAllSprites() {
  preprocessSpriteTwo('heroes', [15,148,62], [252,252,252]);
}

function preprocessSpriteTwo(name, bg1, bg2, tol=30) {
  const img = SPRITES[name];
  if(!img) return;
  const oc = document.createElement('canvas');
  oc.width = img.width; oc.height = img.height;
  const ctx = oc.getContext('2d');
  ctx.drawImage(img, 0, 0);
  const idata = ctx.getImageData(0,0,img.width,img.height);
  const d = idata.data;
  for(let i=0;i<d.length;i+=4){
    const r=d[i],g=d[i+1],b=d[i+2];
    const m1 = Math.abs(r-bg1[0])<tol && Math.abs(g-bg1[1])<tol && Math.abs(b-bg1[2])<tol;
    const m2 = Math.abs(r-bg2[0])<tol && Math.abs(g-bg2[1])<tol && Math.abs(b-bg2[2])<tol;
    if(m1||m2) d[i+3]=0;
  }
  ctx.putImageData(idata,0,0);
  SPRITE_CANVASES[name]=oc;
  console.log('Sprite processed:', name, img.width+'x'+img.height);
}

